from typing import List

def num_islands2(m: int, n: int, positions: List[List[int]]) -> List[int]:
    parent = list(range(m * n))
    rank = [0] * (m * n)

    def find(x: int) -> int:
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x: int, y: int) -> bool:
        px, py = find(x), find(y)
        if px == py:
            return False
        if rank[px] < rank[py]:
            parent[px] = py
        elif rank[px] > rank[py]:
            parent[py] = px
        else:
            parent[py] = px
            rank[px] += 1
        return True

    grid = [[0] * n for _ in range(m)]
    count = 0
    result: List[int] = []
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    for i, j in positions:
        if grid[i][j] == 1:
            result.append(count)
            continue
        grid[i][j] = 1
        count += 1
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and grid[ni][nj] == 1:
                if union(i * n + j, ni * n + nj):
                    count -= 1
        result.append(count)
    return result
